function ttaShortPrompt(groupId: string, itemKey: string, lang: 'zh' | 'en') {
  const g = TTA_SHORT[groupId];
  const rec = g?.[itemKey];
  if (!rec) return lang === 'zh' ? '示例音频' : 'Sample audio';
  return lang === 'zh' ? rec.zh : rec.en;
}

function ttaPromptSrc(item: TtaItem): string {
  return demofileMp3('音效生成', '文生音效 TTA', ...item.pathParts, '提示词.txt');
}

function ttaAudioSrc(item: TtaItem): string {
  return demofileMp3('音效生成', '文生音效 TTA', ...item.pathParts, item.audioFile);
}

function ttaPromptKey(groupId: string, itemKey: string): string {
  return `tta-${groupId}-${itemKey}`;
}

