export default function SoundGenerationIntro({ onBack, onNavigateToExperience }: SoundGenerationIntroProps) {
  const { lang } = useLanguage();
  const t = getT(lang);
  const gi = t.genIntro;

  const [abilityTab, setAbilityTab] = useState<'ac' | 'tc' | 'v2a' | 'tta'>('tta');
  const [tcGroupId, setTcGroupId] = useState(TC_V2A_GROUPS[0]?.id ?? 'tc-l0');
  const [v2aGroupId, setV2aGroupId] = useState(V2A_GROUPS[0]?.id ?? 'v2a-nature');
  const [ttaGroupId, setTtaGroupId] = useState(TTA_GROUPS[0]?.id ?? 'tta-animal');
  const [showMainContent, setShowMainContent] = useState(false);
  const [showBelowFold, setShowBelowFold] = useState(false);

  /** TC-V2A / TTA：从 提示词.txt 加载，与示例一一对应 */
  const [promptMap, setPromptMap] = useState<Record<string, string>>({});
  const promptsLoadedRef = useRef(false);

  /** 视频 V2A：主画面 + 侧栏缩略（对齐 audiodemo） */
  const [v2aFileIdx, setV2aFileIdx] = useState(0);
  /** TTA：全局单路播放（对齐 audiodemo 文生音效区） */
  const ttaAudioRef = useRef<HTMLAudioElement | null>(null);
  const [ttaPlayingId, setTtaPlayingId] = useState<string | null>(null);

  useEffect(() => { window.scrollTo({ top: 0, behavior: 'instant' }); }, []);
  useEffect(() => { setV2aFileIdx(0); }, [v2aGroupId]);

  useEffect(() => {
    return () => {
      if (ttaAudioRef.current) {
        ttaAudioRef.current.pause();
        ttaAudioRef.current.src = '';
        ttaAudioRef.current = null;
      }
    };
  }, []);

  const pauseTta = () => {
    ttaAudioRef.current?.pause();
    setTtaPlayingId(null);
  };

  const toggleTtaPlay = (playKey: string, url: string) => {
    if (ttaPlayingId === playKey) {
      ttaAudioRef.current?.pause();
      setTtaPlayingId(null);
      return;
    }
    let audio = ttaAudioRef.current;
    if (!audio) {
      audio = new Audio();
      audio.addEventListener('ended', () => setTtaPlayingId(null));
      ttaAudioRef.current = audio;
    }
    audio.pause();
    audio.currentTime = 0;
    audio.src = url;
    audio
      .play()
      .then(() => setTtaPlayingId(playKey))
      .catch(() => setTtaPlayingId(null));
  };

  useEffect(() => {
    const t1 = window.setTimeout(() => setShowMainContent(true), 50);
    return () => clearTimeout(t1);
  }, []);
  useEffect(() => {
    const t2 = window.setTimeout(() => setShowBelowFold(true), 250);
    return () => clearTimeout(t2);
  }, []);

  useEffect(() => {
    if (!showMainContent || !showBelowFold) return;
    if (promptsLoadedRef.current) return;
    promptsLoadedRef.current = true;

    const load = async () => {
      const tcLoads = TC_V2A_GROUPS.flatMap((g) => g.items).map((item) => ({
        key: item.key,
        src: item.promptSrc,
      }));
      const ttaLoads = TTA_GROUPS.flatMap((g) =>
        g.items.map((it) => ({
          key: ttaPromptKey(g.id, it.key),
          src: ttaPromptSrc(it),
        })),
      );
      await Promise.all(
        [...tcLoads, ...ttaLoads].map(async ({ key, src }) => {
          try {
            const res = await fetch(src);
            const txt = (await res.text()).trim();
            setPromptMap((prev) => ({ ...prev, [key]: txt }));
          } catch {
            setPromptMap((prev) => ({ ...prev, [key]: '' }));
          }
        }),
      );
    };
    load();
  }, [showMainContent, showBelowFold]);

  const showcaseTitle = lang === 'zh' ? '音效展示' : 'Sound showcase';
  const showcaseSub = lang === 'zh'
    ? '选择能力类型与示例子类，查看对应素材'
    : 'Choose a capability and subcategory to view demos';

  const activeTcGroup = TC_V2A_GROUPS.find((g) => g.id === tcGroupId) ?? TC_V2A_GROUPS[0];
  const activeV2aGroup = V2A_GROUPS.find((g) => g.id === v2aGroupId) ?? V2A_GROUPS[0];
  const activeTtaGroup = TTA_GROUPS.find((g) => g.id === ttaGroupId) ?? TTA_GROUPS[0];

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 animate-in fade-in duration-300 relative">
      {/* Back button — always visible for immediate feedback when entering from 能力介绍 */}
      <button
        onClick={onBack}
        className="fixed top-4 sm:top-6 left-4 sm:left-6 z-50 flex items-center text-gray-600 hover:text-primary transition-colors group"
      >
        <div className="p-1.5 rounded-full bg-gray-100 group-hover:bg-blue-50 transition-colors mr-2">
          <ArrowLeft className="w-4 h-4" />
        </div>
        <span className="font-medium text-sm sm:text-base">{t.common.backHome}</span>
      </button>

      {/* First frame only: title so page is not blank; avoids full-page spinner feel */}
      {!showMainContent && (
        <section className="pt-24 sm:pt-28 px-4 sm:px-6 max-w-[1500px] mx-auto">
          <h1 className="text-2xl sm:text-3xl font-bold text-gray-900">{gi.title}</h1>
        </section>
      )}

      {showMainContent && (
      <>
      {/* Hero */}
      <section className="pt-20 sm:pt-24 pb-8 sm:pb-12 px-4 sm:px-6 lg:px-12 max-w-[1500px] mx-auto">
        <div className="flex flex-col lg:flex-row items-center gap-8 sm:gap-12">
          <div className="w-full lg:w-1/2">
            <div className="mb-4 sm:mb-6">
              <div className="inline-flex items-center gap-2 px-3 py-1 bg-blue-50 text-blue-600 rounded-full text-sm font-semibold">
                <Zap size={14} />
                <span>{gi.badge}</span>
              </div>
            </div>
            <h1 className="text-4xl sm:text-5xl lg:text-6xl font-extrabold mb-4 sm:mb-6 leading-tight">
              {gi.title}
            </h1>
            <p className="text-base sm:text-xl text-gray-600 leading-relaxed mb-6 sm:mb-8">{gi.desc}</p>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
              <div className="flex items-center gap-2 text-gray-700 font-medium bg-gray-50 px-3 sm:px-4 py-2 rounded-lg text-sm sm:text-base">
                <Mic className="text-purple-500" size={18} />{gi.tag1}
              </div>
              <div className="flex items-center gap-2 text-gray-700 font-medium bg-gray-50 px-3 sm:px-4 py-2 rounded-lg text-sm sm:text-base">
                <Video className="text-blue-500" size={18} />{gi.tag2}
              </div>
              <div className="flex items-center gap-2 text-gray-700 font-medium bg-gray-50 px-3 sm:px-4 py-2 rounded-lg text-sm sm:text-base">
                <Type className="text-orange-500" size={18} />{gi.tag3}
              </div>
              <div className="flex items-center gap-2 text-gray-700 font-medium bg-gray-50 px-3 sm:px-4 py-2 rounded-lg text-sm sm:text-base">
                <Music className="text-pink-500" size={18} />{gi.tag4}
              </div>
            </div>
            {onNavigateToExperience && (
              null
            )}
          </div>
          <div className="w-full lg:w-1/2 flex justify-center">
            <div className="relative w-full max-w-xs sm:max-w-sm lg:max-w-lg aspect-square bg-gradient-to-br from-blue-100 to-indigo-50 rounded-full flex items-center justify-center p-6 sm:p-8">
              <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 rounded-full"></div>
              <div className="grid grid-cols-2 gap-3 sm:gap-4 w-full h-full relative z-10">
                <div className="bg-white rounded-2xl shadow-lg p-4 sm:p-6 flex flex-col items-center justify-center transform translate-y-4">
                  <Video className="w-8 h-8 sm:w-12 sm:h-12 text-blue-500 mb-2 sm:mb-4" />
                  <span className="font-bold text-gray-800 text-sm sm:text-base">{lang === 'zh' ? '视觉理解' : 'Visual Understanding'}</span>
                </div>
                <div className="bg-white rounded-2xl shadow-lg p-4 sm:p-6 flex flex-col items-center justify-center transform -translate-y-4">
                  <Activity className="w-8 h-8 sm:w-12 sm:h-12 text-indigo-500 mb-2 sm:mb-4" />
                  <span className="font-bold text-gray-800 text-sm sm:text-base">{lang === 'zh' ? '物理模拟' : 'Physics Simulation'}</span>
                </div>
                <div className="bg-white rounded-2xl shadow-lg p-4 sm:p-6 flex flex-col items-center justify-center transform translate-y-4">
                  <Mic className="w-8 h-8 sm:w-12 sm:h-12 text-purple-500 mb-2 sm:mb-4" />
                  <span className="font-bold text-gray-800 text-sm sm:text-base">{lang === 'zh' ? '文本控制' : 'Text Control'}</span>
                </div>
                <div className="bg-white rounded-2xl shadow-lg p-4 sm:p-6 flex flex-col items-center justify-center transform -translate-y-4">
                  <Music className="w-8 h-8 sm:w-12 sm:h-12 text-pink-500 mb-2 sm:mb-4" />
                  <span className="font-bold text-gray-800 text-sm sm:text-base">{lang === 'zh' ? '高保真音频' : 'Hi-Fi Audio'}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Technical Features */}
      <section className="py-6 sm:py-8 bg-white px-4 sm:px-6 lg:px-12">
        <div className="max-w-[1400px] mx-auto">
          <h2 className="text-2xl sm:text-3xl font-bold mb-6 sm:mb-8 text-center">{gi.techTitle}</h2>
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-5 sm:gap-8">
            {[
              { icon: <Cpu size={24} />, color: 'blue', title: gi.feature1Title, desc: gi.feature1Desc },
              { icon: <Music size={24} />, color: 'purple', title: gi.feature2Title, desc: gi.feature2Desc },
              { icon: <Activity size={24} />, color: 'indigo', title: gi.feature3Title, desc: gi.feature3Desc },
            ].map((f, i) => (
              <div key={i} className="bg-white p-6 sm:p-8 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition-shadow">
                <div className={`w-10 h-10 sm:w-12 sm:h-12 bg-${f.color}-100 rounded-xl flex items-center justify-center text-${f.color}-600 mb-4 sm:mb-6`}>
                  {f.icon}
                </div>
                <h3 className="text-lg sm:text-xl font-bold mb-2 sm:mb-3">{f.title}</h3>
                <p className="text-gray-600 leading-relaxed text-sm sm:text-base">{f.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>
      </>
      )}

      {/* 音效展示：版式对齐 demo-web-front_V2/audiodemo */}
      {showMainContent && showBelowFold && (
      <section className="py-12 bg-white px-4 sm:px-6 lg:px-12">
        <div className="max-w-[1400px] mx-auto">
          <h2 className="text-2xl sm:text-3xl font-bold mb-2 text-center text-blue-600">{showcaseTitle}</h2>
          <p className="text-center text-gray-500 text-sm sm:text-base mb-8">{showcaseSub}</p>

          {/* 一级 Tabs */}
          <div className="flex flex-wrap justify-center gap-3 mb-6">
            {MAIN_TAB_META.map((tab) => {
              const isActive = abilityTab === tab.id;
              const label = lang === 'zh' ? tab.labelZh : tab.labelEn;
              return (
                <button
                  key={tab.id}
                  type="button"
                  onClick={() => {
                    pauseTta();
                    setAbilityTab(tab.id);
                  }}
                  className={`px-4 sm:px-6 py-2 sm:py-2.5 rounded-full font-bold transition-all text-xs sm:text-sm shadow-sm ${
                    isActive
                      ? 'bg-blue-600 text-white shadow-blue-200 scale-105'
                      : 'bg-white text-gray-600 hover:bg-gray-50 border border-gray-200'
                  }`}
                >
                  {label}
                </button>
              );
            })}
          </div>

          {/* TTA：与 audiodemo 相同 — 灰底圆角容器 + 渐变二级标签 + 卡片播放 */}
          {abilityTab === 'tta' && activeTtaGroup && (
            <div className="bg-gray-50 rounded-3xl p-6 lg:p-8 border border-gray-100 shadow-sm animate-in fade-in duration-500 min-h-[320px]">
              <div className="flex flex-wrap justify-center gap-3 mb-8">
                {TTA_GROUPS.map((group) => {
                  const isActive = ttaGroupId === group.id;
                  const title = lang === 'zh' ? group.labelZh : group.labelEn;
                  return (
                    <button
                      key={group.id}
                      type="button"
                      onClick={() => {
                        pauseTta();
                        setTtaGroupId(group.id);
                      }}
                      className={`px-5 sm:px-6 py-2 sm:py-2.5 rounded-lg font-medium transition-all text-sm ${
                        isActive
                          ? 'bg-gradient-to-r from-orange-500 to-pink-500 text-white shadow-lg'
                          : 'bg-white text-gray-600 border border-gray-200 hover:border-gray-300'
                      }`}
                    >
                      {title}
                    </button>
                  );
                })}
              </div>

              <div className="mb-6">
                <div className="flex items-center gap-3">
                  <div className="w-1.5 h-6 bg-blue-500 rounded-full shrink-0" />
                  <h3 className="text-xl font-bold text-gray-800">
                    {lang === 'zh' ? activeTtaGroup.labelZh : activeTtaGroup.labelEn}
                  </h3>
                </div>
              </div>

              <div className="flex flex-wrap justify-center gap-3 sm:gap-4">
                {activeTtaGroup.items.map((it) => {
                  const pk = ttaPromptKey(activeTtaGroup.id, it.key);
                  const playKey = `${activeTtaGroup.id}-${it.key}`;
                  const isPlaying = ttaPlayingId === playKey;
                  const name = lang === 'zh' ? it.labelZh : it.labelEn;
                  const promptText = ttaShortPrompt(activeTtaGroup.id, it.key, lang);
                  return (
                    <div
                      key={it.key}
                      className="bg-white rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all p-4 flex flex-col gap-3 w-full sm:w-[calc(50%-0.5rem)] lg:w-[280px] max-w-full"
                    >
                      <div className="flex items-start gap-3">
                        <span className="text-2xl shrink-0" aria-hidden>🎵</span>
                        <div className="flex-1 min-w-0">
                          <p className="text-gray-800 font-bold text-sm">{name}</p>
                          <p className="text-xs text-gray-500 mt-1 line-clamp-4 leading-relaxed">{promptText}</p>
                        </div>
                        <button
                          type="button"
                          onClick={() => toggleTtaPlay(playKey, ttaAudioSrc(it))}
                          className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 transition-all ${
                            isPlaying
                              ? 'bg-gradient-to-r from-orange-500 to-pink-500 text-white'
                              : 'bg-gradient-to-r from-purple-400 to-purple-500 text-white hover:from-purple-500 hover:to-purple-600'
                          }`}
                          aria-label={isPlaying ? 'Pause' : 'Play'}
                        >
                          {isPlaying ? <Pause size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" className="ml-0.5" />}
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* AC / TC / V2A：audiodemo 灰底容器 + 蓝系二级 Tab */}
          {abilityTab !== 'tta' && (
            <div className="bg-gray-50 rounded-3xl p-6 lg:p-8 border border-gray-100 shadow-sm animate-in fade-in duration-500">
              {abilityTab === 'tc' && (
                <div className="flex flex-wrap justify-center gap-2 mb-8 border-b border-gray-200 pb-4">
                  {TC_V2A_GROUPS.map((group) => {
                    const isActive = tcGroupId === group.id;
                    const title = lang === 'zh' ? group.labelZh : group.labelEn;
                    return (
                      <button
                        key={group.id}
                        type="button"
                        onClick={() => setTcGroupId(group.id)}
                        className={`px-4 py-1.5 rounded-md font-medium transition-all text-sm ${
                          isActive ? 'bg-blue-100 text-blue-700' : 'text-gray-500 hover:text-gray-800 hover:bg-gray-100'
                        }`}
                      >
                        {title}
                      </button>
                    );
                  })}
                </div>
              )}

              {abilityTab === 'v2a' && (
                <div className="flex flex-wrap justify-center gap-2 mb-8 border-b border-gray-200 pb-4">
                  {V2A_GROUPS.map((group) => {
                    const isActive = v2aGroupId === group.id;
                    const title = lang === 'zh' ? group.labelZh : group.labelEn;
                    return (
                      <button
                        key={group.id}
                        type="button"
                        onClick={() => setV2aGroupId(group.id)}
                        className={`px-4 py-1.5 rounded-md font-medium transition-all text-sm ${
                          isActive ? 'bg-blue-100 text-blue-700' : 'text-gray-500 hover:text-gray-800 hover:bg-gray-100'
                        }`}
                      >
                        {title}
                      </button>
                    );
                  })}
                </div>
              )}

              {abilityTab === 'ac' && (
                <div className="mb-6">
                  <div className="flex items-center gap-3">
                    <div className="w-1.5 h-6 bg-blue-500 rounded-full shrink-0" />
                    <h3 className="text-xl font-bold text-gray-800">
                      {lang === 'zh' ? '参考音频与输出视频' : 'Reference audio and output video'}
                    </h3>
                  </div>
                </div>
              )}

              {abilityTab === 'tc' && activeTcGroup && (
                <div className="mb-6">
                  <div className="flex items-center gap-3">
                    <div className="w-1.5 h-6 bg-blue-500 rounded-full shrink-0" />
                    <h3 className="text-xl font-bold text-gray-800">
                      {lang === 'zh' ? activeTcGroup.labelZh : activeTcGroup.labelEn}
                    </h3>
                  </div>
                </div>
              )}

              {abilityTab === 'v2a' && activeV2aGroup && (
                <div className="mb-6">
                  <div className="flex items-center gap-3">
                    <div className="w-1.5 h-6 bg-blue-500 rounded-full shrink-0" />
                    <h3 className="text-xl font-bold text-gray-800">
                      {lang === 'zh' ? activeV2aGroup.labelZh : activeV2aGroup.labelEn}
                    </h3>
                  </div>
                </div>
              )}

              {/* AC-V2A：参考音频与输出视频同卡展示，无箭头 */}
              {abilityTab === 'ac' && (
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                  {AC_V2A_EXAMPLES.map((ex) => (
                    <div key={ex.key} className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden p-4 sm:p-6">
                      <div className="space-y-3">
                        <div className="rounded-xl border border-gray-200 bg-white p-2 sm:p-3">
                          <p className="sr-only">
                            {lang === 'zh' ? '参考音频' : 'Reference audio'}
                          </p>
                          <div className="rounded-xl overflow-hidden bg-white">
                            <audio src={ex.refAudioSrc} controls className="w-full h-10 block" preload="metadata" />
                          </div>
                        </div>
                        <div className="rounded-xl border border-gray-200 bg-white p-2 sm:p-3">
                          <p className="sr-only">
                            {lang === 'zh' ? '输出视频' : 'Output video'}
                          </p>
                          <div className="rounded-xl overflow-hidden bg-gray-900 aspect-video shadow">
                            <LazyVideo
                              src={ex.outputVideoSrc}
                              className="w-full h-full object-cover"
                              controls
                              muted
                              playsInline
                              preload="metadata"
                              onPlay={(e) => { e.currentTarget.muted = false; }}
                            />
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              {/* TC-V2A：输入 → 输出 + 提示词 */}
              {abilityTab === 'tc' && activeTcGroup && (
                <div className="flex flex-col gap-8">
                  {activeTcGroup.items.map((ex) => (
                    <div key={ex.key} className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden p-4 sm:p-6">
                      {promptMap[ex.key] ? (
                        <div className="mb-3">
                          <p className="text-sm text-gray-600">
                            <span className="font-medium text-gray-500">{lang === 'zh' ? '提示词：' : 'Prompt: '}</span>
                            {promptMap[ex.key]}
                          </p>
                        </div>
                      ) : null}
                      <div className="flex flex-col lg:flex-row items-center gap-4 sm:gap-6">
                        <div className="w-full lg:flex-1">
                          <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-1 sm:mb-2">
                            {lang === 'zh' ? '输入' : 'Input'}
                          </p>
                          <div className="rounded-xl overflow-hidden bg-gray-900 aspect-video shadow">
                            <LazyVideo
                              src={ex.inputSrc}
                              className="w-full h-full object-cover"
                              controls
                              muted
                              playsInline
                              preload="metadata"
                              onPlay={(e) => { e.currentTarget.muted = false; }}
                            />
                          </div>
                        </div>
                        <div className="flex-shrink-0 flex items-center justify-center rotate-90 lg:rotate-0">
                          <div className="w-9 h-9 sm:w-10 sm:h-10 rounded-full flex items-center justify-center shadow-sm border bg-blue-50 border-blue-200">
                            <ArrowRight size={16} className="text-blue-600" />
                          </div>
                        </div>
                        <div className="w-full lg:flex-1">
                          <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-1 sm:mb-2">
                            {lang === 'zh' ? '输出' : 'Output'}
                          </p>
                          <div className="rounded-xl overflow-hidden bg-gray-900 aspect-video shadow">
                            <LazyVideo
                              src={ex.outputSrc}
                              className="w-full h-full object-cover"
                              controls
                              muted
                              playsInline
                              preload="metadata"
                              onPlay={(e) => { e.currentTarget.muted = false; }}
                            />
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              {/* 视频 V2A：主预览 + 侧栏列表（同 audiodemo） */}
              {abilityTab === 'v2a' && activeV2aGroup && (() => {
                const files = activeV2aGroup.files.slice(0, 3);
                return (
                  <div className="w-full">
                    <div className="flex flex-wrap justify-center gap-4">
                      {files.map((fn) => (
                        <div key={fn} className="w-full sm:w-[320px] md:w-[360px]">
                          <div className="relative rounded-2xl overflow-hidden shadow-lg bg-black aspect-video border border-gray-200">
                            <LazyVideo
                              src={demofileMp4('音效生成', '视频音效生成V2A', activeV2aGroup.folderZh, fn)}
                              className="w-full h-full object-contain"
                              controls
                              muted
                              playsInline
                              preload="metadata"
                              onPlay={(e) => { e.currentTarget.muted = false; }}
                            />
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })()}
            </div>
          )}
        </div>
      </section>
      )}
    </div>
  );
}
