import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ProductCapabilities from './components/ProductCapabilities';
import AIExperiencePage from './components/AIExperiencePage';
import SoundGenerationIntro from './components/SoundGenerationIntro';
import SoundEditingIntro from './components/SoundEditingIntro';
import { LanguageProvider } from './contexts/LanguageContext';
import DevPanel from './components/DevPanel';
import { trackVisit } from './utils/visitorTracker';

export default function App() {
  const [experienceTab, setExperienceTab] = useState<string | null>(null);
  const [introPage, setIntroPage] = useState<string | null>(null);
  const [showDevPanel, setShowDevPanel] = useState(false);

  // Track visit once on mount
  useEffect(() => {
    trackVisit();
  }, []);

  // Hidden keyboard shortcut: Ctrl + Shift + D → toggle developer panel
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'D') {
        e.preventDefault();
        setShowDevPanel((v) => !v);
      }
    };
    window.addEventListener('keydown', handler);
    // Also expose via console for easy access
    (window as any).showDevPanel = () => setShowDevPanel(true);
    return () => window.removeEventListener('keydown', handler);
  }, []);

  if (experienceTab) {
    return (
      <LanguageProvider>
        {showDevPanel && <DevPanel onClose={() => setShowDevPanel(false)} />}
        <AIExperiencePage
          onBack={() => setExperienceTab(null)}
          initialTab={experienceTab}
        />
      </LanguageProvider>
    );
  }

  if (introPage === 'gen') {
    return (
      <LanguageProvider>
        {showDevPanel && <DevPanel onClose={() => setShowDevPanel(false)} />}
        <SoundGenerationIntro
          onBack={() => setIntroPage(null)}
          onNavigateToExperience={(tabId) => {
            setIntroPage(null);
            setExperienceTab(tabId);
          }}
        />
      </LanguageProvider>
    );
  }
  if (introPage === 'edit') {
    return (
      <LanguageProvider>
        {showDevPanel && <DevPanel onClose={() => setShowDevPanel(false)} />}
        <SoundEditingIntro onBack={() => setIntroPage(null)} />
      </LanguageProvider>
    );
  }
  return (
    <LanguageProvider>
      {showDevPanel && <DevPanel onClose={() => setShowDevPanel(false)} />}
      <div className="min-h-screen bg-white text-gray-900 font-sans selection:bg-blue-100">
        <Navbar />
        <main className="pt-20">
          <Hero onEnterExperience={() => setExperienceTab('gen')} />
          <ProductCapabilities
            onNavigateToExperience={(tabId) => setExperienceTab(tabId)}
            onNavigateToIntro={(tabId) => setIntroPage(tabId)}
          />
        </main>
      </div>
    </LanguageProvider>
  );
}
